export const PARTNER_LIST = Object.values(PARTNER)

export function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
}

export function resolvePartner(input) {
  if (!input) return null
  const trimmed = String(input).trim()
  const direct = PARTNER[slugify(trimmed)]
  if (direct) return direct
  for (const token of trimmed.split(/[\/|,]/)) {
    const m = PARTNER[slugify(token)]
    if (m) return m
  }
  return null
}
